import { createLocalStoreStorage } from '@kyokuya/react-storage'
import { useEffect } from 'react'
import type { MagicPanelType, PostItem } from './types'

/**
 * Data type provided by PostLayoutContext.
 */
export interface PostLayoutContextData {
  /**
   * Whether if enable the darken mode
   */
  darken: boolean
  /**
   * Page brightness
   */
  brightness: number
  /**
   * All of post tags.
   */
  tags: ReadonlyArray<string>
  /**
   * All of post items.
   */
  posts: ReadonlyArray<PostItem>
  /**
   * Keyword in the searching panel.
   */
  searchingKeyword: string
  /**
   * Whether if the tags-list on the searching panel is visible
   */
  searchingTagsVisible: boolean
  /**
   * Whether to display the magic-panel.
   */
  magicPanelVisible: boolean
  /**
   * Which magic-panel should be displayed.
   */
  magicPanelActivated: MagicPanelType
}

export const initialPostLayoutContextData: PostLayoutContextData = {
  darken: false,
  brightness: 100,
  tags: [],
  posts: [],
  searchingKeyword: '',
  searchingTagsVisible: false,
  magicPanelVisible: false,
  magicPanelActivated: 'navigation',
}

const storage = createLocalStoreStorage<Partial<PostLayoutContextData>>(
  '@kyokuya/post-layout-post/context',
  JSON,
)

export const initializePostLayoutContextData = (
  arg?: Partial<PostLayoutContextData>,
): PostLayoutContextData => {
  const partialData: Partial<PostLayoutContextData> = storage.load() ?? {}
  return {
    ...initialPostLayoutContextData,
    ...arg,
    ...partialData,
  }
}

export function usePostLayoutContextDataChangeEffect(
  data: PostLayoutContextData,
): void {
  const {
    darken,
    brightness,
    searchingKeyword,
    searchingTagsVisible,
    magicPanelVisible,
    magicPanelActivated,
  } = data
  useEffect(() => {
    storage.dump({
      darken,
      brightness,
      searchingKeyword,
      searchingTagsVisible,
      magicPanelVisible,
      magicPanelActivated,
    })
  }, [
    darken,
    brightness,
    searchingKeyword,
    searchingTagsVisible,
    magicPanelVisible,
    magicPanelActivated,
  ])
}
